import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Revenue Payment","description":"","frontmatter":{"title":"Revenue Payment"},"headers":[],"relativePath":"en/publishers/payouts.md","filePath":"en/publishers/payouts.md"}'),i={name:"en/publishers/payouts.md"};function n(s,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="revenue-and-payment-management" tabindex="-1">Revenue and Payment Management <a class="header-anchor" href="#revenue-and-payment-management" aria-label="Permalink to &quot;Revenue and Payment Management&quot;">​</a></h1><p>Track your earnings in real-time and optimize your cash flow to avoid fees.</p><h2 id="p-l-tracking-wallet" tabindex="-1">P&amp;L Tracking (Wallet) <a class="header-anchor" href="#p-l-tracking-wallet" aria-label="Permalink to &quot;P&amp;L Tracking (Wallet)&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Your revenue is visible in real-time on the platform.</p><p>Check your <strong>Available Balance</strong> at any time = <em>(Validated revenue) - (Made withdrawals)</em>.</p></div><h3 id="when-does-my-revenue-become-available" tabindex="-1">When does my revenue become available? <a class="header-anchor" href="#when-does-my-revenue-become-available" aria-label="Permalink to &quot;When does my revenue become available?&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>📅 Validation timeline</strong></p><ol><li><strong>Distributed campaign:</strong> The day you confirm distribution (batch shipped, volumes declared).</li><li><strong>Buffer period (30 days):</strong> Your revenue remains <em>pending</em> for 30 days → allows detecting anomalies (lost boxes, interrupted campaign).</li><li><strong>✅ Validated revenue:</strong> After 30 days without incident, the amount moves to <em>Available Balance</em> and can be withdrawn.</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Normal case (no problem)</p><p>Day 1: Distribution confirmed → Day 31: Revenue becomes available → You can withdraw.</p></div><div class="warning custom-block"><p class="custom-block-title">Anomaly detected during the 30 days</p><p>E.g., lost boxes, blocked campaign → We contact you to resolve. The delay can be extended until settlement.</p></div><h2 id="withdrawal-policy-and-fees" tabindex="-1">Withdrawal Policy and Fees <a class="header-anchor" href="#withdrawal-policy-and-fees" aria-label="Permalink to &quot;Withdrawal Policy and Fees&quot;">​</a></h2><p>We encourage pooling payments to limit administrative friction.</p><h3 id="fee-structure-according-to-your-offer" tabindex="-1">Fee Structure according to your Offer <a class="header-anchor" href="#fee-structure-according-to-your-offer" aria-label="Permalink to &quot;Fee Structure according to your Offer&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Offer</th><th>Withdrawal fee</th></tr></thead><tbody><tr><td>🟡 Starter</td><td>1st withdrawal/year: <strong>FREE</strong> · Subsequent: <strong>5%</strong> (e.g., 1,000€ withdrawn → 950€ received)</td></tr><tr><td>🟢 Platform &amp; Managed</td><td><strong>FREE</strong> — all withdrawals, unlimited</td></tr></tbody></table><blockquote><p><strong>Not sure about your offer?</strong> Check your account workspace → Subscription, or consult the <a href="/handbook/en/publishers/pricing.html">Pricing page</a>.</p></blockquote><h3 id="payment-delays" tabindex="-1">Payment Delays <a class="header-anchor" href="#payment-delays" aria-label="Permalink to &quot;Payment Delays&quot;">​</a></h3><div class="gi-value-grid"><div class="gi-value-card"><strong>📄 Prerequisites</strong><p>Submit your <strong>compliant invoice</strong> with the withdrawal request. Without a valid invoice, the payment cannot be processed.</p></div><div class="gi-value-card"><strong>🏦 Payment Delay</strong><p><strong>30 days end of month</strong> after validation of your request.<br>E.g., request validated in March → payment before end of April.</p></div><div class="gi-value-card"><strong>💰 Minimum Amount</strong><p><strong>No set minimum.</strong> Withdraw as soon as you have an available balance.</p></div></div><h3 id="required-actions-to-credit-your-wallet" tabindex="-1">Required actions to credit your Wallet <a class="header-anchor" href="#required-actions-to-credit-your-wallet" aria-label="Permalink to &quot;Required actions to credit your Wallet&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Your revenue is not credited automatically</p><p>The Wallet balance is only updated <strong>after a manual action on your part</strong> depending on the format:</p></div><table tabindex="0"><thead><tr><th>Format</th><th>Required action</th><th>Where on the platform</th></tr></thead><tbody><tr><td>📦 Parcel Insert</td><td>Declare volumes every <strong>Monday or Tuesday</strong></td><td>My Campaigns → campaign → Declare volume</td></tr><tr><td>📧 Emailing (Dedicated or Display)</td><td>Click on <strong>&quot;Validate broadcast&quot;</strong> after sending</td><td>My Campaigns → campaign → Validate broadcast</td></tr></tbody></table><h2 id="how-to-avoid-the-5-fees-starter-offer-only" tabindex="-1">How to avoid the 5% fees? <em>(Starter Offer only)</em> <a class="header-anchor" href="#how-to-avoid-the-5-fees-starter-offer-only" aria-label="Permalink to &quot;How to avoid the 5% fees? *(Starter Offer only)*&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Option A: The &quot;Rollover&quot;</strong><p>Let your revenue accumulate in your pot. By spacing your withdrawals, withdraw your revenue once a year — a pooled withdrawal <strong>without fees</strong>.</p></div><div class="gi-value-card"><strong>Option B: Reinvestment</strong><p>Use your balance to finance your own acquisition campaigns (Parcel Insert or Emailing). 1€ earned = 1€ reinvested in traffic, without banking friction.</p></div></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>💡 Why this policy?</strong></p><ol><li><strong>Admin Reduction:</strong> Limiting the volume of small transfers allows us to maintain low platform costs.</li><li><strong>Security (Buffer):</strong> This cash flow delay secures funds in case of advertiser defaults, guaranteeing you get paid even if the advertiser is late.</li></ol></div><h2 id="⚠️-fund-expiration-rule" tabindex="-1">⚠️ Fund expiration rule <a class="header-anchor" href="#⚠️-fund-expiration-rule" aria-label="Permalink to &quot;⚠️ Fund expiration rule&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Funds expire after 12 months of inactivity</p><p>If you do not log in <strong>AND</strong> do not withdraw your revenue for <strong>12 consecutive months</strong>, the available funds expire and are definitively acquired by getinside.</p><p><strong>How to avoid this:</strong> log in regularly, or enable balance notifications on your account space.</p></div><h2 id="how-to-make-a-withdrawal" tabindex="-1">How to make a withdrawal? <a class="header-anchor" href="#how-to-make-a-withdrawal" aria-label="Permalink to &quot;How to make a withdrawal?&quot;">​</a></h2><ol><li>Log in to your distributor portal at <strong>getinside.io</strong></li><li>Go to <strong>My Account → Wallet / P&amp;L</strong></li><li>Check your <strong>Available Balance</strong> (only this amount is withdrawable)</li><li>Click on <strong>Request a transfer</strong></li><li>Enter the desired amount and confirm your IBAN</li><li>Validate the request → you will receive a confirmation email</li></ol><p><strong>Delay:</strong> 30 days end of month after validation of your request and receipt of your invoice.</p><h2 id="in-case-of-problem" tabindex="-1">In case of problem <a class="header-anchor" href="#in-case-of-problem" aria-label="Permalink to &quot;In case of problem&quot;">​</a></h2><p>Your balance does not match your expectations? A withdrawal is delayed?</p><p>→ Consult the <a href="/handbook/en/faq/troubleshooting-distributors.html">Wallet &amp; Payments Troubleshooting</a> guide for common cases and their solutions.</p><hr><p><strong>Next step:</strong> Boost your revenue with the <a href="/handbook/en/publishers/score-distributor.html">Distributor Score</a> — the higher your score, the more campaigns you receive.</p>',31)])])}const p=a(i,[["render",n]]);export{m as __pageData,p as default};
